@namespace Lumeo
@typeparam TItem

<div class="relative w-full overflow-auto" @attributes="AdditionalAttributes">
    @* role="grid" + aria-row/colcount give AT the table's shape. aria-rowcount
       counts the actually-rendered role=row elements (data/skeleton rows + the
       header row), so it stays truthful while loading (skeleton rows, not the
       provisional Items count) and in the empty state (the "No results"
       placeholder is NOT a grid row, so it isn't counted). aria-multiselectable
       is only set when the selection checkboxes are present. Consumer-supplied
       <th>/<td> in the Header/Row templates keep their native table semantics;
       we add row/cell roles on the markup we own (rows + the selection column). *@
    <table class="@CssClass"
           role="grid"
           aria-rowcount="@AriaRowCount"
           aria-colcount="@(AriaColCount > 0 ? AriaColCount : null)"
           aria-multiselectable="@(Selectable ? "true" : null)">
        <thead class="[&_tr]:border-b [&_tr]:border-border/40" role="rowgroup">
            <tr class="border-b border-border/40 transition-colors hover:bg-muted/50" role="row" aria-rowindex="1">
                @if (Selectable)
                {
                    <th class="h-10 w-10 px-2 text-left align-middle font-medium text-muted-foreground" role="columnheader" scope="col">
                        <Checkbox Checked="@IsAllSelected" IsIndeterminate="@IsSomeSelected" CheckedChanged="@ToggleSelectAll" AriaLabel="Select all rows" />
                    </th>
                }
                @HeaderTemplate
            </tr>
        </thead>
        <tbody class="[&_tr:last-child]:border-0" role="rowgroup">
            @if (IsLoading)
            {
                @for (var i = 0; i < SkeletonRows; i++)
                {
                    <tr class="border-b border-border/40" role="row" aria-hidden="true">
                        @LoadingTemplate
                    </tr>
                }
            }
            else if (Items is null || !Items.Any())
            {
                @* The "No results" placeholder is presentational, not a data row.
                   Marking it role=row/gridcell would announce a phantom grid cell
                   that aria-rowcount (which counts only real rows) does not include,
                   misannouncing the grid shape — so it carries no grid roles. *@
                <tr>
                    <td colspan="100" class="p-8">
                        @if (EmptyTemplate is not null)
                        {
                            @EmptyTemplate
                        }
                        else
                        {
                            <div class="flex flex-col items-center justify-center py-8 text-center">
                                <p class="text-sm text-muted-foreground">No results.</p>
                            </div>
                        }
                    </td>
                </tr>
            }
            else if (Virtualize)
            {
                <Microsoft.AspNetCore.Components.Web.Virtualization.Virtualize Items="@_itemsList" Context="item" SpacerElement="tr" ItemSize="@(ItemSize > 0 ? ItemSize : 41f)">
                    @* Keyed identically to the non-virtualized path so Blazor
                       diffs rows by identity, not position — without this the
                       virtualized rows were unkeyed and recycling reused the
                       wrong row state (checkbox/edit state) when scrolling. *@
                    <tr @key="DataGridRowKeys.KeyFor(item)" class="border-b border-border/40 transition-colors hover:bg-muted/50" role="row" aria-selected="@(Selectable ? (IsSelected(item) ? "true" : "false") : null)">
                        @if (Selectable)
                        {
                            <td class="w-10 px-2 py-2 align-middle" role="gridcell">
                                <Checkbox Checked="@(IsSelected(item))" CheckedChanged="@(c => ToggleItem(item, c))" AriaLabel="Select row" />
                            </td>
                        }
                        @RowTemplate!(item)
                    </tr>
                </Microsoft.AspNetCore.Components.Web.Virtualization.Virtualize>
            }
            else
            {
                @foreach (var item in _itemsList)
                {
                    <tr @key="DataGridRowKeys.KeyFor(item)" class="border-b border-border/40 transition-colors hover:bg-muted/50" role="row" aria-selected="@(Selectable ? (IsSelected(item) ? "true" : "false") : null)">
                        @if (Selectable)
                        {
                            <td class="w-10 px-2 py-2 align-middle" role="gridcell">
                                <Checkbox Checked="@(IsSelected(item))" CheckedChanged="@(c => ToggleItem(item, c))" AriaLabel="Select row" />
                            </td>
                        }
                        @RowTemplate!(item)
                    </tr>
                }
            }
        </tbody>
    </table>
</div>

@code {
    /// <summary>The rows to render. Enumerated once per parameter set into <c>_itemsList</c>; <see langword="null"/> or empty renders <see cref="EmptyTemplate"/> (or the built-in "No results" placeholder) instead of the table body.</summary>
    [Parameter] public IEnumerable<TItem>? Items { get; set; }
    /// <summary>Header cells rendered inside the single <c>&lt;tr&gt;</c> of <c>&lt;thead&gt;</c>, after the selection checkbox column (if <see cref="Selectable"/> is on). Typically one <c>&lt;th&gt;</c> per column, e.g. via <see cref="DataTableSortableHeader"/>.</summary>
    [Parameter] public RenderFragment? HeaderTemplate { get; set; }
    /// <summary>Per-row content, rendered once for each item in <see cref="Items"/> and given the current item as its context. Typically one <c>&lt;td&gt;</c> per column.</summary>
    [Parameter] public RenderFragment<TItem>? RowTemplate { get; set; }
    /// <summary>Content rendered inside each skeleton row while <see cref="IsLoading"/> is <see langword="true"/>. Rendered <see cref="SkeletonRows"/> times.</summary>
    [Parameter] public RenderFragment? LoadingTemplate { get; set; }
    /// <summary>Content shown in place of the table body when <see cref="Items"/> is <see langword="null"/> or empty. Falls back to a centered "No results." message when unset.</summary>
    [Parameter] public RenderFragment? EmptyTemplate { get; set; }
    /// <summary>Shows <see cref="SkeletonRows"/> loading rows (via <see cref="LoadingTemplate"/>) instead of the real data while <see langword="true"/>.</summary>
    [Parameter] public bool IsLoading { get; set; }
    /// <summary>Number of skeleton rows rendered while <see cref="IsLoading"/> is <see langword="true"/>. Default 5.</summary>
    [Parameter] public int SkeletonRows { get; set; } = 5;
    /// <summary>Additional CSS classes merged onto the <c>&lt;table&gt;</c> element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Captures any unmatched attributes and applies them to the outer scrollable wrapper <c>&lt;div&gt;</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Sorting
    /// <summary>The currently sorted column's identifier, as set by a header (e.g. <see cref="DataTableSortableHeader.Column"/>). Two-way bindable via <see cref="SortColumnChanged"/>; the table itself does not sort <see cref="Items"/> — sorting is left to the consumer.</summary>
    [Parameter] public string? SortColumn { get; set; }
    /// <summary>Raised when <see cref="SortColumn"/> changes.</summary>
    [Parameter] public EventCallback<string?> SortColumnChanged { get; set; }
    /// <summary>The current sort direction for <see cref="SortColumn"/>. Default <see cref="SortDirection.Ascending"/>.</summary>
    [Parameter] public SortDirection SortDir { get; set; } = SortDirection.Ascending;
    /// <summary>Raised when <see cref="SortDir"/> changes.</summary>
    [Parameter] public EventCallback<SortDirection> SortDirChanged { get; set; }
    /// <summary>Raised when a sortable header is clicked, with the target column and its new direction. Combine with <see cref="SortColumn"/>/<see cref="SortDir"/> (or their two-way bindings) to actually re-order <see cref="Items"/>.</summary>
    [Parameter] public EventCallback<(string Column, SortDirection Direction)> OnSort { get; set; }

    // Selection
    /// <summary>Enables row selection: renders a checkbox column (with a "select all" checkbox in the header) and <c>aria-selected</c>/<c>aria-multiselectable</c> on the grid.</summary>
    [Parameter] public bool Selectable { get; set; }
    /// <summary>The currently selected rows. Two-way bindable via <see cref="SelectedItemsChanged"/>; membership is decided by <see cref="ItemKey"/> when supplied, otherwise by reference/value equality.</summary>
    [Parameter] public HashSet<TItem>? SelectedItems { get; set; }
    /// <summary>Raised with a new <see cref="HashSet{T}"/> whenever selection changes (row toggle or select-all). Always a fresh instance so <c>@bind-SelectedItems</c> and change detection see the update.</summary>
    [Parameter] public EventCallback<HashSet<TItem>> SelectedItemsChanged { get; set; }

    /// <summary>
    /// Optional stable-key selector for selection membership. When <c>TItem</c>
    /// is a plain reference type (not a record / value type), the default
    /// <see cref="HashSet{T}"/> compares by object reference — so refreshing
    /// <see cref="Items"/> with new instances that are value-equal but
    /// reference-distinct silently drops the selection highlight. Supply a key
    /// (e.g. <c>p =&gt; p.Id</c>) and membership is decided by that key instead
    /// of reference identity, so selection survives a same-content refresh.
    /// When null, membership falls back to <c>SelectedItems.Contains(item)</c>
    /// (reference/value equality), preserving the original behaviour.
    /// </summary>
    [Parameter] public Func<TItem, object>? ItemKey { get; set; }

    /// <summary>
    /// Total column count reported via <c>aria-colcount</c> on the grid
    /// (including the selection column when <see cref="Selectable"/> is on).
    /// Set this when the header/row templates render a fixed number of columns
    /// so assistive tech can announce "column X of N". 0 (default) omits the
    /// attribute since the count can't be inferred from consumer templates.
    /// </summary>
    [Parameter] public int AriaColCount { get; set; }

    // Virtualization
    /// <summary>Virtualize the row list using Blazor's &lt;Virtualize&gt; — only renders rows in the viewport.</summary>
    [Parameter] public bool Virtualize { get; set; }
    /// <summary>Estimated row height in pixels used by the virtualizer (default 41). Only relevant when <see cref="Virtualize"/> is true.</summary>
    [Parameter] public float ItemSize { get; set; } = 48;

    private string CssClass => $"w-full caption-bottom text-sm {Class}".Trim();

    // aria-rowcount must match the role=row elements actually rendered in <tbody>
    // plus the single header row (+1), or AT announces a grid shape that doesn't
    // exist. While loading we render SkeletonRows (the provisional Items count is
    // not yet shown); in the empty state the "No results" placeholder carries no
    // grid roles, so only the header row counts.
    private int AriaRowCount =>
        IsLoading ? Math.Max(SkeletonRows, 0) + 1
        : (Items is null || !Items.Any()) ? 1
        : _itemsList.Count + 1;

    // Cached per-render — recomputed in OnParametersSet to avoid repeated LINQ on every render pass.
    private List<TItem> _itemsList = [];
    private bool _isAllSelected;
    private bool _isSomeSelected;
    // When ItemKey is supplied, selection membership is decided by stable key
    // rather than object reference, so it survives a same-content Items refresh
    // (new value-equal-but-reference-distinct instances). Rebuilt from
    // SelectedItems whenever parameters change.
    private HashSet<object>? _selectedKeys;

    private bool IsAllSelected => _isAllSelected;
    private bool IsSomeSelected => _isSomeSelected;

    // Membership decision used by every row's checkbox/aria-selected. With a key
    // selector, two distinct instances that share a key are treated as the same
    // selected row; without one, this is the original reference/value compare.
    private bool IsSelected(TItem item)
    {
        if (_selectedKeys is not null)
            return _selectedKeys.Contains(ItemKey!(item));
        return SelectedItems?.Contains(item) == true;
    }

    protected override void OnParametersSet()
    {
        _itemsList = Items?.ToList() ?? [];
        _selectedKeys = ItemKey is not null && SelectedItems is not null
            ? new HashSet<object>(SelectedItems.Select(ItemKey))
            : null;
        RefreshSelectionCache();
    }

    // Selection mutations emit a NEW HashSet each time rather than mutating the
    // bound instance in place. Mutating-in-place broke `@bind-SelectedItems`:
    // the parent's field still pointed at the same reference, so SetParametersAsync
    // saw "no change" and downstream comparisons / change detection no-opped.
    // Returning a fresh set gives the callback a distinct identity per change —
    // the ref-stable contract two-way binding and EventCallback consumers expect.
    private async Task ToggleSelectAll(bool select)
    {
        // An empty (or fully-filtered-out) table has nothing to select: treat
        // empty Items the same as null so a select-all toggle is a true no-op —
        // it must NOT emit a spurious SelectedItemsChanged(empty) event. The
        // header checkbox already renders unchecked here (_isAllSelected requires
        // _itemsList.Count > 0), so this keeps the control and its callback aligned.
        if (Items is null || !Items.Any()) return;
        var next = select ? new HashSet<TItem>(Items) : new HashSet<TItem>();
        SelectedItems = next;
        _selectedKeys = ItemKey is not null ? new HashSet<object>(next.Select(ItemKey)) : null;
        RefreshSelectionCache();
        await SelectedItemsChanged.InvokeAsync(next);
    }

    private async Task ToggleItem(TItem item, bool selected)
    {
        var next = SelectedItems is null ? new HashSet<TItem>() : new HashSet<TItem>(SelectedItems);
        if (ItemKey is not null)
        {
            // Decide membership by key so a value-equal-but-reference-distinct
            // instance toggles the row the user clicked, not a phantom duplicate.
            var key = ItemKey(item);
            if (selected)
            {
                if (!next.Any(i => Equals(ItemKey(i), key))) next.Add(item);
            }
            else
            {
                next.RemoveWhere(i => Equals(ItemKey(i), key));
            }
            _selectedKeys = new HashSet<object>(next.Select(ItemKey));
        }
        else
        {
            if (selected) next.Add(item);
            else next.Remove(item);
        }
        SelectedItems = next;
        RefreshSelectionCache();
        await SelectedItemsChanged.InvokeAsync(next);
    }

    private void RefreshSelectionCache()
    {
        _isAllSelected = _itemsList.Count > 0 && SelectedItems is not null && _itemsList.All(IsSelected);
        _isSomeSelected = SelectedItems is not null && SelectedItems.Count > 0 && !_isAllSelected;
    }

    public enum SortDirection { None, Ascending, Descending }
}

@namespace Lumeo

<th class="@CssClass" @attributes="AdditionalAttributes">
    <button type="button" class="inline-flex items-center gap-1 -ml-3 h-8 px-3 rounded-md hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2" @onclick="HandleSort">
        @ChildContent
        @if (SortColumn == Column)
        {
            @if (SortDirection == DataTable<object>.SortDirection.Ascending)
            {
                <SvgGlyph Svg="@(LumeoIcons.ArrowUp)" class="h-3.5 w-3.5" />
            }
            else if (SortDirection == DataTable<object>.SortDirection.Descending)
            {
                <SvgGlyph Svg="@(LumeoIcons.ArrowDown)" class="h-3.5 w-3.5" />
            }
            else
            {
                <SvgGlyph Svg="@(LumeoIcons.ArrowUpDown)" class="h-3.5 w-3.5 opacity-50" />
            }
        }
        else
        {
            <SvgGlyph Svg="@(LumeoIcons.ArrowUpDown)" class="h-3.5 w-3.5 opacity-50" />
        }
    </button>
</th>

@code {
    /// <summary>The header's label content, rendered before the sort direction icon inside the clickable button.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Identifier for the column this header controls. Compared against <see cref="SortColumn"/> to decide which sort icon to show and passed back on <see cref="OnSort"/>.</summary>
    [Parameter, EditorRequired] public string Column { get; set; } = "";
    /// <summary>The <see cref="DataTable{TItem}"/>'s currently sorted column, typically bound to <c>DataTable.SortColumn</c>. When it matches <see cref="Column"/>, the header shows an active (ascending/descending) icon instead of the neutral one.</summary>
    [Parameter] public string? SortColumn { get; set; }
    /// <summary>The current sort direction for this column when it is the active <see cref="SortColumn"/>, typically bound to <c>DataTable.SortDir</c>.</summary>
    [Parameter] public DataTable<object>.SortDirection SortDirection { get; set; }
    /// <summary>Raised on click with this header's <see cref="Column"/> and the next direction in the ascending → descending → none cycle.</summary>
    [Parameter] public EventCallback<(string Column, DataTable<object>.SortDirection Direction)> OnSort { get; set; }
    /// <summary>Additional CSS classes merged onto the <c>&lt;th&gt;</c> element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Captures any unmatched attributes and applies them to the <c>&lt;th&gt;</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"h-10 px-2 text-left align-middle font-medium text-muted-foreground {Class}".Trim();

    private async Task HandleSort()
    {
        var newDirection = SortColumn == Column
            ? SortDirection switch
            {
                DataTable<object>.SortDirection.Ascending => DataTable<object>.SortDirection.Descending,
                DataTable<object>.SortDirection.Descending => DataTable<object>.SortDirection.None,
                _ => DataTable<object>.SortDirection.Ascending
            }
            : DataTable<object>.SortDirection.Ascending;

        await OnSort.InvokeAsync((Column, newDirection));
    }
}
